 18→class BloggingPromptCardViewHolder(
 19→    parent: ViewGroup,
 20→    private val uiHelpers: UiHelpers,
 21→    private val bloggingPromptsCardAnalyticsTracker: BloggingPromptsCardAnalyticsTracker,
 22→    private val htmlCompatWrapper: HtmlCompatWrapper,
 23→    private val learnMoreClicked: () -> Unit
 24→) : MySiteCardAndItemViewHolder<MySiteBloggingPromptCardBinding>(
 25→    parent.viewBinding(MySiteBloggingPromptCardBinding::inflate)
 26→) {
 27→    fun bind(card: BloggingPromptCardWithData) = with(binding) {
 28→        val cardPrompt = htmlCompatWrapper.fromHtml(
 29→            uiHelpers.getTextOfUiString(promptContent.context, card.prompt).toString()
 30→        )
 31→        uiHelpers.setTextOrHide(promptContent, cardPrompt)
 32→        uiHelpers.updateVisibility(answerButton, !card.isAnswered)
 33→
 34→        uiHelpers.updateVisibility(attributionContainer, card.attribution == DAY_ONE)
 35→
 36→        attributionContent.text = htmlCompatWrapper.fromHtml(
 37→            attributionContent.context.getString(R.string.my_site_blogging_prompt_card_attribution_dayone)
 38→        )
 39→
 40→        bloggingPromptCardMenu.setOnClickListener {
 41→            bloggingPromptsCardAnalyticsTracker.trackMySiteCardMenuClicked()
 42→            showCardMenu(card)
 43→        }
 44→
 45→        answerButton.setOnClickListener {
 46→            card.onAnswerClick.invoke(card.promptId)
 47→        }
 48→        shareButton.setOnClickListener {
 49→            bloggingPromptsCardAnalyticsTracker.trackMySiteCardShareClicked()
 50→            card.onShareClick.invoke(
 51→                uiHelpers.getTextOfUiString(
 52→                    shareButton.context,
 53→                    card.prompt
 54→                ).toString()
 55→            )
 56→        }
 57→        uiHelpers.updateVisibility(answeredPromptControls, card.isAnswered)
 58→
 59→        setupAnsweredUsersContainer(card)
 60→    }
 61→
 62→    @Suppress("NestedBlockDepth")
 63→    private fun setupAnsweredUsersContainer(
 64→        card: BloggingPromptCardWithData,
 65→    ) = with(binding) {
 66→        if (card.numberOfAnswers <= 0) {
 67→            answeredUsersAvatars.isVisible = false
 68→            answeredUsersLabel.isVisible = false
 69→            return@with
 70→        }
 71→
