{"new_string":"    private fun createMoreActions(
        postStatus: PostStatus,
        isLocalDraft: Boolean,
        isLocallyChanged: Boolean,
        uploadUiState: PostUploadUiState,
        siteHasCapabilitiesToPublish: Boolean,
        statsSupported: Boolean,
        shouldShowStatsInJetpackRemovalPhase: Boolean,
        shouldShowPromoteWithBlaze: Boolean,
        postListType: PostListType,
        onButtonClicked: (PostListButtonType) -> Unit
    ): PostListItemAction.MoreItem {
        val actions = mutableListOf<PostListItemAction>()

        val canRetryUpload = uploadUiState is UploadFailed
        val canCancelPendingAutoUpload = (uploadUiState is UploadWaitingForConnection ||
                (uploadUiState is UploadFailed && uploadUiState.isEligibleForAutoUpload))
        val canPublishPost = (canRetryUpload || uploadUiState is NothingToUpload || !canCancelPendingAutoUpload) &&
                (isLocallyChanged || isLocalDraft || postStatus == DRAFT ||
                        (siteHasCapabilitiesToPublish && postStatus == PENDING))

        val canShowStats = statsSupported &&
                postStatus == PUBLISHED &&
                !isLocalDraft &&
                !isLocallyChanged &&
                shouldShowStatsInJetpackRemovalPhase
        val canShowCopy = postStatus == PUBLISHED || postStatus == DRAFT
        val canShowCopyUrlButton = !isLocalDraft && postStatus != TRASHED
        val canShowViewButton = !canRetryUpload && postStatus != TRASHED
        val canShowPublishButton = canRetryUpload || canPublishPost

        // Group IDs
        val groupPrimary = 1
        val groupSecondary = 2
        val groupDestructive = 3

        when (postListType) {
            PostListType.PUBLISHED -> {
                if (canShowStats) actions.add(PostListItemAction.SingleItem(BUTTON_STATS, onButtonClicked, groupPrimary))
                actions.add(PostListItemAction.SingleItem(BUTTON_EDIT, onButtonClicked, groupPrimary))
                if (canShowViewButton) actions.add(PostListItemAction.SingleItem(BUTTON_VIEW, onButtonClicked, groupPrimary))
                if (canShowCopyUrlButton) actions.add(PostListItemAction.SingleItem(BUTTON_COPY_URL, onButtonClicked, groupPrimary))

                if (canShowCopy) actions.add(PostListItemAction.SingleItem(BUTTON_COPY, onButtonClicked, groupSecondary))
                if (shouldShowPromoteWithBlaze) actions.add(
                    PostListItemAction.SingleItem(BUTTON_PROMOTE_WITH_BLAZE, onButtonClicked, groupSecondary)
                )

                actions.add(PostListItemAction.SingleItem(BUTTON_MOVE_TO_DRAFT, onButtonClicked, groupDestructive))
                actions.add(PostListItemAction.SingleItem(BUTTON_TRASH, onButtonClicked, groupDestructive))
            }
            PostListType.DRAFTS -> {
                actions.add(PostListItemAction.SingleItem(BUTTON_EDIT, onButtonClicked, groupPrimary))
                if (canShowViewButton) actions.add(PostListItemAction.SingleItem(BUTTON_PREVIEW, onButtonClicked, groupPrimary))
                if (canShowPublishButton) {
                    val type = when {
                        canRetryUpload -> BUTTON_RETRY
                        !siteHasCapabilitiesToPublish -> BUTTON_SUBMIT
                        else -> BUTTON_PUBLISH
                    }
                    actions.add(PostListItemAction.SingleItem(type, onButtonClicked, groupPrimary))
                }
                if (canCancelPendingAutoUpload) actions.add(
                    PostListItemAction.SingleItem(BUTTON_CANCEL_PENDING_AUTO_UPLOAD, onButtonClicked, groupPrimary)
                )

                if (canShowCopy) actions.add(PostListItemAction.SingleItem(BUTTON_COPY, onButtonClicked, groupSecondary))
                if (canShowCopyUrlButton) actions.add(PostListItemAction.SingleItem(BUTTON_COPY_URL, onButtonClicked, groupSecondary))

                actions.add(PostListItemAction.SingleItem(if (isLocalDraft) BUTTON_DELETE else BUTTON_TRASH, onButtonClicked, groupDestructive))
            }
            PostListType.SCHEDULED -> {
                actions.add(PostListItemAction.SingleItem(BUTTON_EDIT, onButtonClicked, groupPrimary))
                if (canShowViewButton) actions.add(PostListItemAction.SingleItem(BUTTON_PREVIEW, onButtonClicked, groupPrimary))
                if (canShowPublishButton && postStatus == SCHEDULED && isLocallyChanged) {
                    actions.add(PostListItemAction.SingleItem(BUTTON_SYNC, onButtonClicked, groupPrimary))
                }

                if (canShowCopy) actions.add(PostListItemAction.SingleItem(BUTTON_COPY, onButtonClicked, groupSecondary))
                if (canShowCopyUrlButton) actions.add(PostListItemAction.SingleItem(BUTTON_COPY_URL, onButtonClicked, groupSecondary))

                actions.add(PostListItemAction.SingleItem(BUTTON_MOVE_TO_DRAFT, onButtonClicked, groupDestructive))
                actions.add(PostListItemAction.SingleItem(BUTTON_TRASH, onButtonClicked, groupDestructive))
            }
            PostListType.TRASHED -> {
                actions.add(PostListItemAction.SingleItem(BUTTON_MOVE_TO_DRAFT, onButtonClicked, groupPrimary))
                actions.add(PostListItemAction.SingleItem(BUTTON_DELETE_PERMANENTLY, onButtonClicked, groupPrimary))

                if (canShowViewButton) actions.add(PostListItemAction.SingleItem(BUTTON_VIEW, onButtonClicked, groupSecondary))
            }
            else -> { // SEARCH or unknown
                if (postStatus != TRASHED) actions.add(PostListItemAction.SingleItem(BUTTON_EDIT, onButtonClicked, groupPrimary))
                if (canCancelPendingAutoUpload) actions.add(
                    PostListItemAction.SingleItem(BUTTON_CANCEL_PENDING_AUTO_UPLOAD, onButtonClicked, groupPrimary)
                )
                if (canShowPublishButton) {
                    val type = when {
                        canRetryUpload -> BUTTON_RETRY
                        !siteHasCapabilitiesToPublish -> BUTTON_SUBMIT
                        postStatus == SCHEDULED && isLocallyChanged -> BUTTON_SYNC
                        else -> BUTTON_PUBLISH
                    }
                    actions.add(PostListItemAction.SingleItem(type, onButtonClicked, groupPrimary))
                }
                if (canShowViewButton) {
                    val type = if (isLocalDraft || isLocallyChanged) BUTTON_PREVIEW else BUTTON_VIEW
                    actions.add(PostListItemAction.SingleItem(type, onButtonClicked, groupPrimary))
                }
                if (canShowStats) actions.add(PostListItemAction.SingleItem(BUTTON_STATS, onButtonClicked, groupPrimary))

                if (canShowCopy) actions.add(PostListItemAction.SingleItem(BUTTON_COPY, onButtonClicked, groupSecondary))
                if (canShowCopyUrlButton) actions.add(PostListItemAction.SingleItem(BUTTON_COPY_URL, onButtonClicked, groupSecondary))
                if (shouldShowPromoteWithBlaze) actions.add(
                    PostListItemAction.SingleItem(BUTTON_PROMOTE_WITH_BLAZE, onButtonClicked, groupSecondary)
                )

                if (postStatus == PUBLISHED || postStatus == TRASHED) {
                    actions.add(PostListItemAction.SingleItem(BUTTON_MOVE_TO_DRAFT, onButtonClicked, groupDestructive))
                }

                val deleteType = when {
                    isLocalDraft -> BUTTON_DELETE
                    postStatus == TRASHED -> BUTTON_DELETE_PERMANENTLY
                    else -> BUTTON_TRASH
                }
                actions.add(PostListItemAction.SingleItem(deleteType, onButtonClicked, groupDestructive))
            }
        }

        return PostListItemAction.MoreItem(actions, onButtonClicked)
    }
